   177→          text += `⏱️ Sisa: *${formatRemainingTime(remaining)}*\n\n`;
   178→          text += `_Jawab langsung atau ketik "nyerah"_`;
   179→          await sendWithBtn(sock, chatId, text, gameButtons(gameType), m);
