   208→        caption += `💡 Hint: *${getHint(answer, cfg.hintCount)}*\n`;
   209→        caption += `⏱️ Waktu: *${cfg.timeout / 1000} detik*\n`;
   210→        caption += `🎁 Hadiah: *Limit, Koin, EXP (random)*\n\n`;
   211→        caption += `_Jawab langsung atau ketik "nyerah"_`;
   212→
   213→        sentMsg = await sendImageWithBtn(
   214→          sock, chatId, imageBuffer, caption,
   215→          gameButtons(gameType), m,
   216→        );
   217→      } else {
   218→        let text = `${cfg.emoji} *${cfg.title}*\n\n`;
   219→        if (cfg.questionField && question[cfg.questionField]) {
   220→          text += `\`\`\`${question[cfg.questionField]}\`\`\`\n\n`;
   221→        }
