   290→        return true;
   291→      }
   292→
   293→      // ── Button: Nyerah ─────────────────────────────────────────────────────
   294→      if (userAnswer === `${gameType}_nyerah` || isSurrender(userAnswer)) {
   295→        endSession(chatId);
   296→        const answer = session.question[cfg.answerField];
   297→        let text = `${pick(SURRENDER_MESSAGES)}\n\n`;
   298→        text += `Jawaban: *${answer}*\n\n`;
   299→        text += `_@${m.sender.split("@")[0]} menyerah_`;
   300→        await sendGameOver(sock, chatId, text, gameType, m, [m.sender]);
   301→        return true;
   302→      }
   303→
   304→      if (!isReplyToGame(m, session)) return false;
   305→
   306→      session.attempts++;
   307→
   308→      const answer = session.question[cfg.answerField];
   309→      const result = checkAnswerAdvanced(answer, userAnswer);
   310→
   311→      if (result.status === "correct") {
   312→        endSession(chatId);
   313→
   314→        const db = getDatabase();
   315→        const user = db.getUser(m.sender);
   316→
   317→        let totalLimit = 0;
   318→        let totalBalance = 0;
   319→        let totalExp = 0;
   320→
   321→        if (cfg.rewards === false || cfg.rewards === null) {
   322→          // no rewards
   323→        } else if (cfg.rewards) {
   324→          totalLimit = cfg.rewards.limit || cfg.rewards.energi || 0;
   325→          totalBalance = cfg.rewards.koin || cfg.rewards.balance || 0;
   326→          totalExp = cfg.rewards.exp || 0;
   327→        } else {
   328→          const reward = getRandomReward();
   329→          totalLimit = reward.limit;
   330→          totalBalance = reward.koin;
   331→          totalExp = reward.exp;
   332→        }
   333→
   334→        let bonusText = "";
   335→
   336→        const fastResult = checkFastAnswer(session);
   337→        if (
   338→          fastResult.isFast &&
   339→          cfg.rewards !== false &&
   340→          cfg.rewards !== null
   341→        ) {
   342→          totalLimit += fastResult.bonus.limit;
   343→          totalBalance += fastResult.bonus.koin;
   344→          totalExp += fastResult.bonus.exp;
   345→          bonusText = `\n\n${fastResult.praise}\n⚡ *BONUS KILAT:* +${fastResult.bonus.limit} Limit, +${fastResult.bonus.koin} Koin\n⏱️ Waktu: *${(fastResult.elapsed / 1000).toFixed(1)}s*`;
   346→        }
   347→
   348→        if (totalLimit > 0) db.updateEnergi(m.sender, totalLimit);
   349→        if (totalBalance > 0) db.updateKoin(m.sender, totalBalance);
