   351→        if (totalExp > 0) {
   352→          if (!user.rpg) user.rpg = {};
   353→          await addExpWithLevelCheck(sock, m, db, user, totalExp);
   354→        }
   355→        db.save();
   356→
   357→        let text = `${pick(WIN_MESSAGES)}\n\n`;
   358→        text += `Jawaban: *${answer}*\n`;
   359→        text += `Pemenang: *@${m.sender.split("@")[0]}*\n`;
   360→        text += `Percobaan: *${session.attempts}x*\n\n`;
   361→
   362→        if (totalLimit > 0 || totalBalance > 0 || totalExp > 0) {
   363→          let parts = [];
   364→          if (totalLimit > 0) parts.push(`+${totalLimit} Limit`);
   365→          if (totalBalance > 0) parts.push(`+${totalBalance} Koin`);
   366→          if (totalExp > 0) parts.push(`+${totalExp} EXP`);
   367→          text += `🎁 ${parts.join(", ")}`;
   368→        }
   369→        text += bonusText;
   370→
   371→        await sendGameOver(sock, chatId, text, gameType, m, [m.sender]);
   372→        return true;
   373→      }
