   218→function startDevWatcher(pluginsPath) {
   219→  if (pluginWatcher) pluginWatcher.close();
   220→
   221→  logger.system("dev", "Hot-Reload watcher active for plugins");
   222→
   223→  pluginWatcher = fs.watch(
   224→    pluginsPath,
   225→    { recursive: true },
   226→    (eventType, filename) => {
   227→      if (!filename || !filename.endsWith(".js")) return;
   228→
   229→      const existingTimeout = reloadDebounce.get(filename);
   230→      if (existingTimeout) clearTimeout(existingTimeout);
   231→
   232→      const timeout = setTimeout(async () => {
   233→        reloadDebounce.delete(filename);
   234→        const fullPath = path.join(pluginsPath, filename);
   235→
   236→        if (!fs.existsSync(fullPath)) {
   237→          fileStatCache.delete(fullPath);
   238→          const pluginName = path.basename(filename, ".js");
   239→          const { unloadPlugin } = await import("./src/lib/ourin-plugins.js");
   240→          const result = unloadPlugin(pluginName);
   241→          if (result.success) logger.warn("plugin", `removed ${filename}`);
   242→          return;
   243→        }
   244→
   245→        try {
   246→          const stats = fs.statSync(fullPath);
   247→          const cached = fileStatCache.get(fullPath);
   248→          const changed =
   249→            !cached ||
   250→            cached.mtimeMs !== stats.mtimeMs ||
   251→            cached.size !== stats.size;
   252→          if (!changed) return;
   253→
   254→          fileStatCache.set(fullPath, {
   255→            mtimeMs: stats.mtimeMs,
   256→            size: stats.size,
   257→          });
   258→
   259→          const { hotReloadPlugin } =
   260→            await import("./src/lib/ourin-plugins.js");
   261→          const result = await hotReloadPlugin(fullPath);
   262→          if (!result.success) {
   263→            logger.error(
   264→              "plugin",
   265→              `reload failed: ${filename}: ${result.error}`,
   266→            );
   267→          }
   268→        } catch (error) {
   269→          logger.error(
   270→            "plugin",
   271→            `reload failed: ${filename}: ${error.message}`,
   272→          );
   273→        }
   274→      }, 500);
   275→
   276→      reloadDebounce.set(filename, timeout);
   277→    },
   278→  );
   279→
   280→  logger.debug("dev", `Monitoring directory: ${pluginsPath}`);
   281→}
