   312→function setupAntiCrash() {
   313→  process.on("uncaughtException", (error, origin) => {
   314→    const ignoredErrors = [
   315→      "write EOF",
   316→      "ECONNRESET",
   317→      "EPIPE",
   318→      "ETIMEDOUT",
   319→      "ENOTFOUND",
   320→      "ECONNREFUSED",
   321→      "read ECONNRESET",
   322→    ];
   323→    const isIgnored = ignoredErrors.some(
   324→      (msg) => error.message?.includes(msg) || error.code === msg,
   325→    );
   326→    if (isIgnored) return;
   327→
   328→    logErrorBox("uncaught exception", error.message);
   329→    console.error(c.gray(error.stack));
   330→    logger.system("system", "Engine is still running");
   331→  });
   332→
   333→  process.on("unhandledRejection", (reason, promise) => {
   334→    logErrorBox("unhandled rejection", String(reason));
   335→    console.error(c.gray("Promise:"), promise);
   336→    logger.system("system", "Engine is still running");
   337→  });
   338→
   339→  process.on("warning", (warning) => {
   340→    logger.warn("system", `${warning.name}: ${warning.message}`);
   341→  });
   342→
   343→  process.on("SIGINT", async () => {
   344→    console.log("");
   345→    logger.system("system", "Received STOP signal (SIGINT)");
   346→    logger.info("database", "Saving data to local storage...");
   347→    try {
   348→      const db = getDatabase();
   349→      db.save();
   350→      logger.success("database", "All data successfully saved");
   351→    } catch (error) {
   352→      logger.warn("database", `save failed: ${error.message}`);
   353→    }
   354→    logger.info("system", "Engine stopped safely");
   355→    process.exit(0);
   356→  });
   357→
   358→  process.on("SIGTERM", () => {
   359→    console.log("");
   360→    logger.system("system", "Received TERMINATE signal (SIGTERM)");
   361→    process.exit(0);
   362→  });
   363→
   364→  logger.success("system", "Anti-Crash Protection is Active");
   365→}
